<div class="en">
<svg viewBox="0 0 700 700" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="32" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Cango's Rise and Fall — From Mining Pivot to Reverse Split</text>
  <g font-family="sans-serif">
    <rect x="30" y="55" width="640" height="190" rx="10" fill="#1c1c1e" stroke="#71717a" stroke-width="1.2"/>
    <text x="50" y="82" fill="#e4e4e7" font-size="14" font-weight="700">Timeline</text>
    <text x="50" y="108" fill="#a1a1aa" font-size="13">Nov 2024 — Buys 50 EH/s mining capacity for $400M, pivots to mining</text>
    <text x="50" y="132" fill="#a1a1aa" font-size="13">Late 2025 — Mines 6,594 BTC, treasury 7,528.3 BTC, revenue $688M</text>
    <text x="50" y="156" fill="#a1a1aa" font-size="13">Jan 2026 — Stock trades around $1.45</text>
